202	+func dependentsFileTooLargeWarning(path string, size int) ProviderWarning {
203	+	return ProviderWarning{
204	+		Code:                 "E_FILE_TOO_LARGE",
205	+		Severity:             "warning",
206	+		FilePath:             path,
