235	+// tree. The fallback keeps dependent counts correct, but it is far slower
236	+// than the prefiltered path, so callers should know it happened.
237	+func grepFallbackWarning(err error) ProviderWarning {
238	+	return ProviderWarning{
239	+		Code:                 "W_DEPENDENTS_PREFILTER_FAILED",
240	+		Severity:             "warning",
241	+		EffectOnCompleteness: "dependents git-grep prefilter failed; fell back to scanning every file in the tree",
242	+		Detail:               err.Error(),
