246	+// referenceCandidateFiles narrows the head tree to files worth parsing, using
247	+// git grep's fixed-string, case-insensitive substring search as a
248	+// preselection pass. That test is a strict superset of containsIdentifier's
249	+// case-sensitive whole-token check -- a case-sensitive substring is always
250	+// also a case-insensitive one -- so it can only add extra candidate files,
251	+// never drop a real dependent; the per-entity containsIdentifier check below
252	+// still runs unchanged. It uses GrepTreePathsIncludingBinary rather than
253	+// GrepTreePaths specifically to preserve that superset guarantee for files
254	+// Git itself classifies as binary (an embedded NUL byte, or a
255	+// `.gitattributes` binary/-diff marking): a Supported source file flagged
256	+// binary is still real source that gets parsed below, so the prefilter must
257	+// not silently drop it. If the grep call itself fails for any reason, fall
258	+// back to scanning every file in the tree so a git-grep quirk never silently
259	+// zeroes out dependent counts, and surface exactly one warning noting the
260	+// prefilter failure so the fallback (much slower) scan is not silent.
261	+func referenceCandidateFiles(ctx context.Context, repo, head string, names map[string]struct{}) ([]string, []ProviderWarning, error) {
262	+	patterns := make([]string, 0, len(names))
263	+	for name := range names {
