270	+		if grepErr == nil {
271	+			return matches, nil, nil
272	+		}
273	+		files, err := gitutil.ListFiles(ctx, repo, head)
274	+		if err != nil {
275	+			return nil, nil, err
276	+		}
277	+		return files, []ProviderWarning{grepFallbackWarning(grepErr)}, nil
278	+	}
