417	+// paddedPythonSource builds a syntactically valid Python file of exactly
418	+// targetSize bytes: a real function that calls calledName, followed by a
419	+// single padding comment line long enough to reach the target size.
420	+func paddedPythonSource(funcName, calledName string, targetSize int) string {
421	+	prefix := "def " + funcName + "(token):\n    return " + calledName + "(token)\n"
422	+	padNeeded := targetSize - len(prefix) - len("# \n")
423	+	if padNeeded < 0 {
424	+		padNeeded = 0
425	+	}
426	+	return prefix + "# " + strings.Repeat("x", padNeeded) + "\n"
427	+}
