486	+// subprocess invocation fail outright (Go's exec layer rejects NUL bytes in
487	+// arguments), while leaving the unrelated, well-formed pattern's real
488	+// dependents fully discoverable via the fallback scan.
489	+func TestBuildReferenceIndexFallsBackWhenGrepFails(t *testing.T) {
