+		}
+		files, err := gitutil.ListFiles(ctx, repo, head)
+		if err != nil {
+			return nil, nil, err
+		}
+		return files, []ProviderWarning{grepFallbackWarning(grepErr)}, nil
+	}
+	files, err := gitutil.ListFiles(ctx, repo, head)
+	return files, nil, err
